const r = $input.first().json || {};
const { payload, ...rest } = r;
return [{ json: { ok:true, data: rest, error:null } }];

// Unifica a resposta da BrasilAPI e da ReceitaWS num objeto estruturado.
const j = $input.first().json || {};
const cnpj = $('Normalize').item.json.cnpj;
const onlyDigits = (s) => String(s || '').replace(/\D/g, '');
const parseDateBR = (s) => { const m = String(s || '').match(/^(\d{2})\/(\d{2})\/(\d{4})$/); return m ? `${m[3]}-${m[2]}-${m[1]}` : null; };
const parseISO = (s) => { const d = String(s || '').slice(0, 10); return /^\d{4}-\d{2}-\d{2}$/.test(d) ? d : null; };
const toNum = (v) => { if (v === null || v === undefined || v === '') return null; const n = parseFloat(String(v).replace(/\./g, '').replace(',', '.')); return Number.isFinite(n) ? n : (Number.isFinite(parseFloat(v)) ? parseFloat(v) : null); };
const PORTE_MAP = (p) => { const u = String(p || '').toUpperCase(); if (!u) return null; if (u.includes('MEI') || u.includes('MICRO')) return 'pequeno'; if (u.includes('PEQUEN') || u.includes('EPP')) return 'medio'; return 'grande'; };
const isBrasilApi = (j.descricao_situacao_cadastral !== undefined) || (j.cnae_fiscal !== undefined) || (j.razao_social !== undefined);
let o;
if (isBrasilApi) {
  o = {
    razao_social: j.razao_social ?? null,
    nome_fantasia: j.nome_fantasia || null,
    porte_rf: j.porte ?? null,
    cnae_principal: j.cnae_fiscal ? String(j.cnae_fiscal) : null,
    cnae_descricao: j.cnae_fiscal_descricao ?? null,
    cnaes_secundarios: Array.isArray(j.cnaes_secundarios) ? j.cnaes_secundarios.map((c) => ({ codigo: String(c.codigo), descricao: c.descricao })) : [],
    natureza_juridica: j.natureza_juridica ?? null,
    capital_social: toNum(j.capital_social),
    data_abertura: parseISO(j.data_inicio_atividade),
    situacao_cadastral: j.descricao_situacao_cadastral ?? null,
    data_situacao: parseISO(j.data_situacao_cadastral),
    motivo_situacao: j.descricao_motivo_situacao_cadastral || null,
    simples_optante: (typeof j.opcao_pelo_simples === 'boolean') ? j.opcao_pelo_simples : null,
    mei_optante: (typeof j.opcao_pelo_mei === 'boolean') ? j.opcao_pelo_mei : null,
    municipio: j.municipio ?? null,
    uf: j.uf ?? null,
    bairro: j.bairro ?? null,
    cep: j.cep ? onlyDigits(j.cep) : null,
    logradouro: [j.descricao_tipo_de_logradouro, j.logradouro, j.numero].filter(Boolean).join(' ') || null,
    telefone: j.ddd_telefone_1 ?? null,
    email: j.email ?? null,
    socios: Array.isArray(j.qsa) ? j.qsa.map((s) => ({ nome: s.nome_socio, qualificacao: s.qualificacao_socio, faixa_etaria: s.faixa_etaria ?? null })) : [],
  };
} else {
  const ap = Array.isArray(j.atividade_principal) ? j.atividade_principal[0] : null;
  o = {
    razao_social: j.nome ?? null,
    nome_fantasia: j.fantasia || null,
    porte_rf: j.porte ?? null,
    cnae_principal: ap ? onlyDigits(ap.code) : null,
    cnae_descricao: ap ? ap.text : null,
    cnaes_secundarios: Array.isArray(j.atividades_secundarias) ? j.atividades_secundarias.map((c) => ({ codigo: onlyDigits(c.code), descricao: c.text })) : [],
    natureza_juridica: j.natureza_juridica ?? null,
    capital_social: toNum(j.capital_social),
    data_abertura: parseDateBR(j.abertura),
    situacao_cadastral: j.situacao ?? null,
    data_situacao: parseDateBR(j.data_situacao),
    motivo_situacao: j.motivo_situacao || null,
    simples_optante: (j.simples && typeof j.simples.optante === 'boolean') ? j.simples.optante : null,
    mei_optante: (j.simei && typeof j.simei.optante === 'boolean') ? j.simei.optante : null,
    municipio: j.municipio ?? null,
    uf: j.uf ?? null,
    bairro: j.bairro ?? null,
    cep: j.cep ? onlyDigits(j.cep) : null,
    logradouro: [j.logradouro, j.numero].filter(Boolean).join(' ') || null,
    telefone: j.telefone ?? null,
    email: j.email ?? null,
    socios: Array.isArray(j.qsa) ? j.qsa.map((s) => ({ nome: s.nome, qualificacao: s.qual, faixa_etaria: s.faixa_etaria ?? null })) : [],
  };
}
if (!o.razao_social && !o.cnae_principal) { return [{ json: { __cnpj_error: true, cnpj, payload: j } }]; }
o.cnpj = cnpj;
o.porte = PORTE_MAP(o.porte_rf);
o.qtd_socios = Array.isArray(o.socios) ? o.socios.length : 0;
o.idade_anos = o.data_abertura ? Math.max(0, Math.floor((Date.now() - new Date(o.data_abertura).getTime()) / (365.25 * 24 * 3600 * 1000))) : null;
o.payload = j;
return [{ json: o }];
